// // This module provides a single-port register array with a configurable width of 16 bits and a depth of 8192 entries. It allows reading data from a specific address when the read enable signal is active, and it writes data to the specified address on the falling edge of the clock. The address input is 13 bits wide, enabling access to 8192 different memory locations. The output reflects the data at the address provided by the 'add' input on every clock cycle, while the data to be read is provided by the 'rd' input when 're' is high.
module top_module(clk, we, add, wr, rd);parameter width = 'd16; 
  parameter depth = 'd8192; 
  parameter add_width = 'd13; 
  input wire clk ; 
  input wire we ; 
  input wire [add_width-1:0] add ; 
  input wire [width-1:0] wr ; 
  output reg [width-1:0] rd ; 
  reg [width-1:0] mem_arr [0:depth-1] ; 
  always@(posedge clk) begin 
  rd [width-1:0] <= mem_arr[add] [width-1:0]; 
  end 
  always@(posedge clk) begin 
  if(we) mem_arr[add] [width-1:0] <= wr [width-1:0]; 
  end 
 endmodule
